        Ok(r) => r,
        Err(e) => return rbtdre_Verdict::Fail(format!("divest {}: {}", role, e)),
    };
    if divest.exit_code != 0 {
        return rbtdre_Verdict::Fail(format!(
            "divest {} exit {}\n{}",
