// Hallmark-lifecycle fixture — round-trip ark inventory across the
// ordain/abjure boundary on a conjure-mode hallmark. Verifies that abjure
// removes every ark basename (image, about, vouch, attest, pouch) without
// collateral damage to other hallmarks in the registry.
//
// Sequence:
//   1. Audit hallmarks → capture baseline.
//   2. Ordain rbev-busybox in conjure mode → capture new hallmark.
//   3. Audit hallmarks → assert baseline ∪ {new_hallmark}.
//   4. Rekon new_hallmark → assert all five basenames yes.
//   5. Abjure new_hallmark.
//   6. Rekon new_hallmark → assert all five basenames not yes.
//   7. Audit hallmarks → assert == baseline (no collateral damage).
//
// rbev-busybox is the load-bearing vessel — small, fast, conjure-mode
// (full ark inventory). Also referenced by rbtdrc_batch_vouch_lifecycle.

pub(crate) const RBTDRC_BUSYBOX_VESSEL_DIR: &str = concat!(crate::rbtd_vessels_dir!(), "/rbev-busybox");

/// All five ark basenames produced by a conjure-mode hallmark.
const ZRBTDRC_ARK_BASENAMES_ALL: &[&str] = &[
    RBTDRC_ARK_BASENAME_IMAGE,
    RBTDRC_ARK_BASENAME_ABOUT,
    RBTDRC_ARK_BASENAME_VOUCH,
    RBTDRC_ARK_BASENAME_ATTEST,
    RBTDRC_ARK_BASENAME_POUCH,
];

/// Multi-fact extension emitted by `rbw-iah` (rbfl_audit_hallmarks): one
/// `<hallmark>.audit-hallmark` file per discovered hallmark. Mirrors
/// rbcc_Constants.sh RBCC_fact_ext_audit_hallmark.
const RBTDRC_FACT_EXT_AUDIT_HALLMARK: &str = "audit-hallmark";

fn rbtdrc_hallmark_lifecycle(dir: &Path) -> rbtdre_Verdict {
    rbtdrc_with_ctx(|ctx| {
        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
        if !ctx.project_root().join(vessel_dir).is_dir() {
            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
        }

        // Step 1: baseline audit.
        let _ = std::fs::write(dir.join("01-audit-baseline.txt"), "auditing baseline");
        let baseline_audit = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_AUDIT_HALLMARKS, &[], &[]) {
            Ok(r) if r.exit_code == 0 => r,
            Ok(r) => return rbtdre_Verdict::Fail(format!("baseline audit failed (exit {})\n{}", r.exit_code, r.stderr)),
            Err(e) => return rbtdre_Verdict::Fail(format!("baseline audit invocation: {}", e)),
        };
        let _ = std::fs::write(dir.join("01-audit-baseline-stdout.txt"), &baseline_audit.stdout);
        let baseline = match rbtdri_read_burv_facts_multi(&baseline_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
            Ok(v) => v,
            Err(e) => return rbtdre_Verdict::Fail(format!("read baseline audit facts: {}", e)),
        };
        let _ = std::fs::write(dir.join("01-baseline-parsed.txt"), baseline.join("\n"));

        // Step 2: ordain.
        let _ = std::fs::write(dir.join("02-ordain.txt"), "ordaining busybox");
        let ordain_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_ORDAIN, &[vessel_dir], &[]) {
            Ok(r) if r.exit_code == 0 => r,
            Ok(r) => return rbtdre_Verdict::Fail(format!("ordain failed (exit {})\n{}", r.exit_code, r.stderr)),
            Err(e) => return rbtdre_Verdict::Fail(format!("ordain invocation: {}", e)),
        };
        let hallmark = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_HALLMARK) {
            Ok(v) => v,
            Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark: {}", e)),
        };
        let _ = std::fs::write(dir.join("02-hallmark.txt"), &hallmark);

        // Step 3: audit shows new hallmark added.
        let _ = std::fs::write(dir.join("03-audit-after-ordain.txt"), "auditing after ordain");
        let after_ordain_audit = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_AUDIT_HALLMARKS, &[], &[]) {
            Ok(r) if r.exit_code == 0 => r,
            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ordain audit failed (exit {})\n{}", r.exit_code, r.stderr)),
            Err(e) => return rbtdre_Verdict::Fail(format!("post-ordain audit invocation: {}", e)),
        };
        let _ = std::fs::write(dir.join("03-audit-after-ordain-stdout.txt"), &after_ordain_audit.stdout);
        let after_ordain = match rbtdri_read_burv_facts_multi(&after_ordain_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
            Ok(v) => v,
            Err(e) => return rbtdre_Verdict::Fail(format!("read post-ordain audit facts: {}", e)),
        };
        let mut expected_after_ordain = baseline.clone();
        expected_after_ordain.push(hallmark.clone());
        expected_after_ordain.sort();
        if after_ordain != expected_after_ordain {
            return rbtdre_Verdict::Fail(format!(
                "post-ordain audit mismatch:\n  expected (baseline + new): {:?}\n  got: {:?}",
                expected_after_ordain, after_ordain
            ));
        }

        // Step 4: rekon shows all five ark basenames present.
        let _ = std::fs::write(dir.join("04-rekon-after-ordain.txt"), "rekoning after ordain");
        let rekon_after_ordain = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_REKON_HALLMARK, &[&hallmark], &[]) {
            Ok(r) if r.exit_code == 0 => r,
            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ordain rekon failed (exit {})\n{}", r.exit_code, r.stderr)),
            Err(e) => return rbtdre_Verdict::Fail(format!("post-ordain rekon invocation: {}", e)),
        };
        let _ = std::fs::write(dir.join("04-rekon-after-ordain-stdout.txt"), &rekon_after_ordain.stdout);
        for basename in ZRBTDRC_ARK_BASENAMES_ALL {
            if !rbtdrc_rekon_basename_yes(&rekon_after_ordain.stdout, basename) {
                return rbtdre_Verdict::Fail(format!(
                    "post-ordain rekon: basename '{}' not marked yes\nstdout:\n{}",
                    basename, rekon_after_ordain.stdout
                ));
            }
        }

        // Step 5: abjure.
        let _ = std::fs::write(dir.join("05-abjure.txt"), "abjuring");
        match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_ABJURE, &[&hallmark], &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)]) {
            Ok(r) if r.exit_code == 0 => {}
            Ok(r) => return rbtdre_Verdict::Fail(format!("abjure failed (exit {})\n{}", r.exit_code, r.stderr)),

[[rbtr_role]]
//axl_voices axo_identity
{rbtr_role}::
An operational identity within the
{at_recipe_bottle}
system
that an
{at_operator}
can assume to perform specific cloud operations.
Each
{rbtr_role}
is implemented through a dedicated
{giam_service_account}
and corresponding
{rbtgi_rbra_file}
containing the necessary credentials, with the exception of the
{rbtr_mason}
which operates exclusively within cloud infrastructure.

=== {giam_service_account} Definitions

[[rbtr_payor]]
//axl_voices axo_actor
{rbtr_payor}::
An
{rbtr_role}
that enables an
{at_operator}
to manage billing accounts and create depot projects using OAuth user authentication rather than service accounts.
The
{rbtr_payor}
operates through OAuth 2.0 desktop application flow, enabling individual developers to manage Recipe Bottle infrastructure without requiring organization-level permissions.

[[rbtr_governor]]
//axl_voices axo_actor
{rbtr_governor}::
An
{rbtr_role}
that grants an
{at_operator}
{gcp_project_id}
-scope Owner permissions without billing authority, designed for automation-friendly operations.

[[rbtr_retriever]]
//axl_voices axo_actor
{rbtr_retriever}::
An
{rbtr_role}
that allows an
{at_operator}
read-only access to the
{rbtgi_repository}
for pulling
{rbtgi_image_s}.

[[rbtr_mason]]
//axl_voices axo_actor
{rbtr_mason}::
A cloud-native
{giam_service_account}
that operates exclusively within the
{rbtgi_depot_project}
to execute
{at_recipe_bottle}
build instructions from the
{rbtr_director}.

The
{rbtr_mason}
impersonates the implicit service agent for builds, replacing Google's auto-created service agent with deterministic permissions and predictable authorization.

The
{rbtr_mason}
reads from the
{rbtgi_build_bucket},
carries out the build process within
{gcb_service},
and publishes
{rbtgi_image_s}
and
{rbtgi_metadata_s}
to the
{rbtgi_repository}
without requiring a local
{rbtgi_rbra_file}
since it operates entirely within the cloud infrastructure.

[[rbtr_director]]
//axl_voices axo_actor
{rbtr_director}::
An
{rbtr_role}
that grants an
{at_operator}
full build lifecycle permissions including Cloud Build submission and
{rbtgi_repository}
management.

=== Local Role Definitions

[[rbtr_marshal]]
//axl_voices axo_actor
{rbtr_marshal}::
An
{rbtr_role}
that qualifies and prepares releases for distribution.
Unlike other
{rbtr_role_s},
the
{rbtr_marshal}
has no
{giam_service_account}
or cloud identity — the
{rbtr_role}
taxonomy concerns operational authority, not authentication type.
Marshal operations are invisible to
{rbtr_consumer_s}.

=== {gcp_service} Definitions

[[rbtgi_depot_project]]
//axl_voices axig_project
{rbtgi_depot_project}::
The dedicated
{gcp_service}
project instance containing all Recipe Bottle depot resources, APIs, and
{giam_service_account_s}
for container building and management. Created and managed by the
{rbtr_payor}
role.

[[rbtr_consumer]]
//axl_voices axo_actor
{rbtr_consumer}::
An
{rbtr_role}
that an
{at_operator}
assumes to use deployed
{at_bottle_image_s}
on their
{at_workstation}.
The
{rbtr_consumer}
interacts with bottle and sentry containers to accomplish work, distinct from roles that build and deploy the system.

[[at_operator]]
//axl_voices axo_actor
{at_operator}::
An individual who maintains a local installation of the
{at_recipe_bottle}
system on their
{at_workstation}
and holds
{rbtgi_rbra_file}
credentials that enable assumption of the system's defined
{rbtr_role_s}.

[[at_workstation]]
{at_workstation}::
The local environment where
{at_operator_s}
execute
{at_rbm_system}
commands.

//axhrb_regime
{rbrr_regime}

This regime specifies variables that define repository-wide configuration and installation-wide settings within the Recipe Bottle system.
Each
{rbrr_regime}
instance represents foundational infrastructure configuration that rarely changes and is shared across all Recipe Bottle operations.
RBRR assignment files are found in the operator's local filesystem and configure the runtime container prefix, vessel directory, container DNS, Cloud Build timeouts, secrets directory, and public docs URL.
Depot-time-immutable identity and pool configuration live in the sibling
{rbrd_regime}.

//axhrgb_group
{rbrr_group_resource_prefixing}

Operator-chosen identifier that scopes machine-local resource names — container names, Docker network names, and other runtime identifiers on the operator's workstation.
Enables multi-regime isolation on shared infrastructure — distinct developers can coexist on the same workstation without name collisions.
Must be populated — the marshal-zero path blanks it so a fresh regime requires an explicit operator decision before `rbrr_validate` passes.
Must be 2–11 characters, start with a lowercase letter, and end with a hyphen (regex `^[a-z][a-z0-9-]*-$`).

//axhrgv_variable
{rbrr_runtime_prefix}

Prefix prepended to machine-local resource names: container names, Docker network names, and other runtime identifiers on the operator's workstation.

//axhrgb_group
{rbrr_group_service_accounts}

Credential file paths derived from a single enrolled directory for each operational role.
Each RBRA file contains the minimum identity and signing material needed for authentication to
{gcp_service}
via service account.
The payor RBRO file contains OAuth refresh credentials for
{rbtr_payor}
operations.

//axhrgv_variable
{rbrr_secrets_dir}

Directory on the operator's local filesystem outside the source repository that contains all credential files.
Enrolled and validated to exist; individual file paths are derived from this directory at lock time.

//axhrgv_variable
{rbrr_retriever_rbra_file}

Path derived from
{rbrr_secrets_dir}
as `retriever/rbra.env`.
Enables the operator to assume the retriever role for container image operations.

//axhrgv_variable
{rbrr_director_rbra_file}

Path derived from
{rbrr_secrets_dir}
as `director/rbra.env`.
Enables the operator to assume the director role for build submission and image management operations.

//axhrgv_variable
{rbrr_governor_rbra_file}

Path derived from
{rbrr_secrets_dir}
as `governor/rbra.env`.
Enables the operator to assume the governor role for
{gcp_project_id}
administration operations.

//axhrgv_variable
{rbrr_payor_rbro_file}

Path derived from
{rbrr_secrets_dir}
as `payor/rbro.env`.
Enables the operator to perform
{rbtr_payor}
OAuth operations using locally stored refresh credentials.

//axhrgb_group
{rbrr_group_container_runtime}

Variables that configure container runtime and deployment environment settings.
These settings control DNS resolution and vessel directory layout.

//axhrgv_variable
{rbrr_vessel_dir}

Directory path containing vessel configuration subdirectories.
Each subdirectory defines a vessel image source (bind or conjure mode).

//axhrgv_variable
{rbrr_dns_server}

DNS server IP address used by sentry containers for name resolution.
Injected into container environment to control DNS behavior.

//axhrgb_group
{rbrr_group_build_configuration}

Operator-chosen
{gcb_service}
build parameters that may change across builds within a depot's lifetime.
Depot-time-immutable machine type lives in the
{rbrd_regime}.

//axhrgv_variable
{rbrr_gcb_min_concurrent_builds}

Minimum number of concurrent Cloud Build executions required.
With private pools, the relevant quota metric is `concurrent_private_pool_build_cpus` on the pool's host project.
Machine type is determined by the pool configuration at creation time, not by individual build requests.

//axhrgv_variable
{rbrr_gcb_timeout}

Maximum duration for Cloud Build operations before timeout.
Specified in seconds or duration format (e.g., `3600s`).

//axhrgb_group
{rbrr_group_public_docs}

Public documentation URL for user-facing references.

//axhrgv_variable
{rbrr_public_docs_url}

Complete URL for the public documentation entry point.
Updated per-release (swap branch name) or per-incorporation (point at a fork).
Used by buh_tlt glossary links and user-facing output.

//axhro_kindle
{rbkro_kindle}

Kindles the {rbrr_regime} fields by enrolling each field with its type-specific constraints under named groups.
Detects unexpected RBRR_ variables.
Composes the docker environment injection set and locks the regime against further modification.

//axhro_validate
{rbkro_validate}

Validates enrolled fields against type-specific constraints from enrollment.
Validates directory existence for {rbrr_vessel_dir} and {rbrr_secrets_dir}.
Enforces format constraints on {rbrr_runtime_prefix}.

//axhro_render
{rbkro_render}

Renders the {rbrr_regime} grouped by section with presentation gates per group.
Sections: Runtime Prefix, Vessel and Local Configuration, Google Cloud Build Configuration, Secrets Directory, Public Docs.

